effect.shader:
const float PI = 3.14159;

void main() {

    vec2 st = acScreenNorm;
    vec2 center = centerPoint/1000. * vec2(-1.,1.);

    float featherSize = radius*0.5*feather;
    float innerRadius = max(0.0,radius-featherSize);
    float outerRadius = max(innerRadius+0.00001,radius+featherSize);

    st -= acLayerCenterNorm-center;

    st.y *= (acScreenSize.y/acScreenSize.x);

    float dist = length(st);

    float damping = smoothstep(outerRadius,innerRadius,dist);

    vec2 offset = sin((dist*frequency*PI*2.0)+(phase*PI*2.0))*strength/2.0 * normalize(st) * damping;

    st += offset;

    st.y /= (acScreenSize.y/acScreenSize.x);

    st += acLayerCenterNorm-center;

    gl_FragColor = texture2DCv(inputImg.texture,st);

}
